      { referencia: "Salmo 76:7-9", texto: "Tu, sim, tu és tremendo! ... Quando Deus se levantou para julgar, para livrar todos os mansos da terra." },
      { referencia: "Salmo 76:10", texto: "Na verdade a ira do homem redundará em teu louvor; o restante da ira tu o restringirás." },
      { referencia: "Salmo 76:11-12", texto: "Fazei votos, e pagai-os ao Senhor... Ele ceifará o espírito dos príncipes; é tremendo para com os reis da terra." }
